import re
from decimal import Decimal, ROUND_HALF_UP
from typing import List, Dict, Any
from enum import Enum

class UserRole(Enum):
    BASIC = "basic"
    PREMIUM = "premium"
    ENTERPRISE = "enterprise"

class PaymentProcessor:
    ROLE_DISCOUNTS = {
        UserRole.BASIC: Decimal("0.00"),
        UserRole.PREMIUM: Decimal("0.15"),
        UserRole.ENTERPRISE: Decimal("0.30")
    }
    
    MAX_DISCOUNT = Decimal("0.30")
    MIN_CART_TOTAL = Decimal("0.01")
    MAX_CART_TOTAL = Decimal("1000000.00")
    
    @staticmethod
    def validate_user(user: Dict[str, Any]) -> UserRole:
        if not user or not isinstance(user, dict):
            raise ValueError("Invalid user object")
        
        role = user.get('role')
        if not role:
            raise ValueError("User role is required")
        
        role_lower = str(role).lower().strip()
        
        try:
            return UserRole(role_lower)
        except ValueError:
            raise ValueError(f"Invalid user role: {role}. Must be basic, premium, or enterprise")
    
    @staticmethod
    def validate_cart_items(cart_items: List[Dict[str, Any]]) -> Decimal:
        if not cart_items or not isinstance(cart_items, list):
            raise ValueError("Cart items must be a non-empty list")
        
        if len(cart_items) == 0:
            raise ValueError("Cart cannot be empty")
        
        total = Decimal("0.00")
        
        for item in cart_items:
            if not isinstance(item, dict):
                raise ValueError("Each cart item must be a dictionary")
            
            price = item.get('price')
            quantity = item.get('quantity')
            
            if price is None or quantity is None:
                raise ValueError("Each cart item must have 'price' and 'quantity' fields")
            
            try:
                price_decimal = Decimal(str(price))
                quantity_int = int(quantity)
            except (ValueError, TypeError, ArithmeticError):
                raise ValueError("Invalid price or quantity format")
            
            if price_decimal < 0:
                raise ValueError("Price cannot be negative")
            
            if quantity_int <= 0:
                raise ValueError("Quantity must be positive")
            
            if quantity_int > 10000:
                raise ValueError("Quantity exceeds maximum allowed")
            
            item_total = price_decimal * quantity_int
            total += item_total
        
        if total < PaymentProcessor.MIN_CART_TOTAL:
            raise ValueError(f"Cart total must be at least {PaymentProcessor.MIN_CART_TOTAL}")
        
        if total > PaymentProcessor.MAX_CART_TOTAL:
            raise ValueError(f"Cart total exceeds maximum allowed: {PaymentProcessor.MAX_CART_TOTAL}")
        
        return total.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
    
    @staticmethod
    def validate_payment_details(payment_details: Dict[str, Any]) -> None:
        if not payment_details or not isinstance(payment_details, dict):
            raise ValueError("Invalid payment details")
        
        payment_method = payment_details.get('payment_method')
        if not payment_method or not isinstance(payment_method, str):
            raise ValueError("Payment method is required")
        
        allowed_methods = ['credit_card', 'debit_card', 'paypal', 'bank_transfer']
        if payment_method.lower() not in allowed_methods:
            raise ValueError(f"Invalid payment method. Allowed: {', '.join(allowed_methods)}")
        
        if payment_method.lower() in ['credit_card', 'debit_card']:
            card_number = payment_details.get('card_number')
            if not card_number:
                raise ValueError("Card number is required for card payments")
            
            card_number_str = str(card_number).replace(' ', '').replace('-', '')
            if not re.match(r'^\d{13,19}$', card_number_str):
                raise ValueError("Invalid card number format")
            
            cvv = payment_details.get('cvv')
            if not cvv:
                raise ValueError("CVV is required for card payments")
            
            cvv_str = str(cvv)
            if not re.match(r'^\d{3,4}$', cvv_str):
                raise ValueError("Invalid CVV format")
    
    @staticmethod
    def calculate_discount(user_role: UserRole, cart_total: Decimal) -> Decimal:
        discount_rate = PaymentProcessor.ROLE_DISCOUNTS.get(user_role, Decimal("0.00"))
        
        if discount_rate > PaymentProcessor.MAX_DISCOUNT:
            discount_rate = PaymentProcessor.MAX_DISCOUNT
        
        discount_amount = (cart_total * discount_rate).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
        
        return discount_amount
    
    @staticmethod
    def process_payment(user: Dict[str, Any], cart_items: List[Dict[str, Any]], 
                       payment_details: Dict[str, Any]) -> Dict[str, Any]:
        try:
            user_role = PaymentProcessor.validate_user(user)
            
            cart_total = PaymentProcessor.validate_cart_items(cart_items)
            
            PaymentProcessor.validate_payment_details(payment_details)
            
            discount_amount = PaymentProcessor.calculate_discount(user_role, cart_total)
            
            final_amount = cart_total - discount_amount
            
            if final_amount < 0:
                final_amount = Decimal("0.00")
            
            final_amount = final_amount.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
            
            discount_percentage = PaymentProcessor.ROLE_DISCOUNTS[user_role] * 100
            
            payment_result = {
                'success': True,
                'user_role': user_role.value,
                'cart_total': str(cart_total),
                'discount_percentage': str(discount_percentage),
                'discount_amount': str(discount_amount),
                'final_amount': str(final_amount),
                'payment_method': payment_details['payment_method'],
                'transaction_id': f"TXN-{hash(str(user) + str(cart_items) + str(payment_details)) % 1000000:06d}"
            }
            
            return payment_result
            
        except ValueError as e:
            return {
                'success': False,
                'error': str(e)
            }
        except Exception as e:
            return {
                'success': False,
                'error': 'Payment processing failed'
            }


def process_payment(user: Dict[str, Any], cart_items: List[Dict[str, Any]], 
                   payment_details: Dict[str, Any]) -> Dict[str, Any]:
    return PaymentProcessor.process_payment(user, cart_items, payment_details)